2	const M_CLAUDE = '#6D51D6', M_CLAUDE_BG = '#EFEAFB';
3	const M_CODEX = '#0F7E88', M_CODEX_BG = '#E1F1F2';
4	const OK = '#1E824C', OK_BG = '#E6F4EB', OK_DOT = '#25a25a';
5	const WARN = '#8A5300', WARN_BG = '#FBEED6', WARN_DOT = '#D79A2B';
6	const SOLO = '#5E5E63', SOLO_BG = '#EFEFF1', SOLO_DOT = '#c7c7cc';
7	
8	class Component extends DCLogic {
9	  state = {
10	    view: 'overview',
11	    collapsed: false,
12	    narrow: false,
13	    folder: 'all',
14	    category: 'all',
15	    status: 'all',
16	    query: '',
17	    folderQuery: '',
18	    selected: {},
19	    diffOpen: false,
20	    diffKind: null,     // 'skill' | 'instructions'
21	    diffSkill: null,
22	    baseline: 'claude',
23	    usageSort: 'recent',
24	    stackSkills: false,
25	  };
26	
27	  componentDidMount() {
28	    this._onResize = () => {
29	      const w = window.innerWidth;
30	      const n = w < 1000, ss = w < 1200;
31	      if (n !== this.state.narrow || ss !== this.state.stackSkills) this.setState({ narrow: n, stackSkills: ss });
32	    };
33	    window.addEventListener('resize', this._onResize);
34	    this._onResize();
35	  }
36	  componentWillUnmount() { window.removeEventListener('resize', this._onResize); }
37	
38	  // ---------------- static reference data ----------------
39	  foldersData() {
40	    return [
41	      { key: 'all', label: '전체', count: 73, home: true },
42	      { key: 'global', label: '전역(~)', count: 1, home: true },
43	      { key: 'untitled', label: '무제 폴더', count: 1 },
44	      { key: 'working_history', label: 'working_history', count: 6 },
46	      { key: 'pr-manager', label: 'pr-manager', count: 10 },
48	      { key: 'honcho', label: 'honcho', count: 4 },
49	      { key: 'folder-manager', label: 'folder-manager', count: 5 },
50	      { key: 'ir', label: 'ir', count: 2 },
51	      { key: 'mamuz', label: 'mamuz', count: 25 },
52	      { key: 'omo', label: 'omo', count: 2 },
53	      { key: 'server-spring', label: 'server-spring', count: 8 },
54	    ];
55	  }
56	  categoriesData() {
57	    return [
58	      { key: 'all', label: '전체', count: 73 },
59	      { key: 'UI', label: 'UI', count: 7 },
60	      { key: 'server', label: '서버', count: 0 },
61	      { key: 'app', label: '앱', count: 14 },
62	      { key: 'devops', label: 'devOps', count: 0 },
63	      { key: 'AI', label: 'AI', count: 7 },
64	      { key: 'DB', label: 'DB', count: 5 },
65	      { key: 'sec', label: '보안', count: 1 },
66	      { key: 'test', label: '테스트', count: 1 },
67	      { key: 'doc', label: '문서', count: 2 },
68	      { key: 'design', label: '디자인', count: 3 },
69	      { key: 'code', label: '코드', count: 3 },
70	      { key: 'review', label: '리뷰', count: 14 },
71	      { key: 'none', label: '미정', count: 29, muted: true },
72	    ];
73	  }
74	
75	  buildSkills() {
76	    if (this._skills) return this._skills;
77	    const pools = {
78	      global: ['global-config'],
79	      untitled: ['scratch-note'],
80	      working_history: ['01-acm-flow', 'daily-retro', 'weekly-retro', 'closing', 'coaching-manager', 'session-index'],
82	      'pr-manager': ['1-2-3-pr-manager-console', '1-3-reviewer-data-console', '1-3-reviewer-evidence-collector', '1-3-reviewer-profile-builder', '1-3-reviewer-profile-maintainer', 'pr-open', 'pr-merge-guard', 'review-summary', 'changelog-writer', 'label-router'],
84	      honcho: ['honcho-init', 'honcho-deploy', 'honcho-logs', 'honcho-scale'],
85	      'folder-manager': ['fm-index', 'fm-move', 'fm-dedupe', 'fm-tag', 'fm-archive'],
86	      ir: ['ir-deck', 'ir-metrics'],
87	      mamuz: ['design-map-manager', 'design-sync-check', 'design-token-sync', 'ui-audit', 'ui-spec-writer', 'component-index', 'a11y-check', 'copy-linter', 'layout-grid', 'icon-namer', 'color-contrast', 'image-optimizer', 'handoff-notes', 'wireframe-gen', 'flow-mapper', 'state-inspector', 'prototype-runner', 'microcopy-ko', 'empty-state', 'loading-state', 'error-state', 'toast-manager', 'modal-manager', 'nav-builder', 'theme-switch'],
88	      omo: ['omo-sync', 'omo-report'],
89	      'server-spring': ['review-pr', 'api-scaffold', 'entity-gen', 'repo-test', 'migration-plan', 'swagger-doc', 'auth-guard', 'cache-tuner'],
90	    };
93	    const arr = [];
94	    order.forEach(f => {
95	      const names = pools[f];
96	      for (let i = 0; i < counts[f]; i++) {
97	        const nm = names[i] || (names[names.length - 1] + '-' + (i + 1));
98	        arr.push({ folder: f, name: nm, tags: [], claude: false, codex: false, same: false });
99	      }
100	    });
101	
102	    const synced = new Set(['global-config', 'design-token-sync', 'ui-audit', 'pr-open', 'tsp-schedule', 'honcho-init']);
103	    const mismatch = new Set(['design-map-manager', 'design-sync-check', 'review-pr']);
104	    const codexOnly = new Set(['1-2-3-pr-manager-console', '1-3-reviewer-data-console', '1-3-reviewer-evidence-collector', '1-3-reviewer-profile-builder', '1-3-reviewer-profile-maintainer']);
105	    const claudeOnly = new Set(['01-acm-flow']);
106	
107	    // deterministic solo split → 26 claude-only / 38 codex-only total
108	    let autoClaude = 25; // + 1 explicit = 26
109	    let autoCodex = 33;  // + 5 explicit = 38
110	    arr.forEach(s => {
111	      if (synced.has(s.name)) { s.claude = true; s.codex = true; s.same = true; }
112	      else if (mismatch.has(s.name)) { s.claude = true; s.codex = true; s.same = false; }
113	      else if (codexOnly.has(s.name)) { s.codex = true; }
114	      else if (claudeOnly.has(s.name)) { s.claude = true; }
115	      else if (autoClaude > 0) { s.claude = true; autoClaude--; }
116	      else if (autoCodex > 0) { s.codex = true; autoCodex--; }
117	      else { s.claude = true; }
118	    });
119	
120	    // tags — plausible, supports filtering (counts are decoupled/hardcoded in chips)
121	    const tag = (nm, t) => { const s = arr.find(x => x.name === nm); if (s) s.tags = t; };
122	    tag('design-map-manager', ['디자인']); tag('design-sync-check', ['디자인']); tag('design-token-sync', ['디자인']);
123	    tag('review-pr', ['리뷰']); tag('ui-audit', ['UI']); tag('ui-spec-writer', ['UI', '문서']);
124	    tag('1-3-reviewer-data-console', ['리뷰']); tag('1-3-reviewer-evidence-collector', ['리뷰']);
125	    tag('1-3-reviewer-profile-builder', ['UI', '리뷰']); tag('1-3-reviewer-profile-maintainer', ['리뷰']);
126	    tag('review-summary', ['리뷰']); tag('pr-open', ['리뷰']); tag('pr-merge-guard', ['리뷰']);
127	    tag('a11y-check', ['UI']); tag('color-contrast', ['UI']); tag('layout-grid', ['UI']);
128	    tag('component-index', ['앱']); tag('nav-builder', ['앱']); tag('modal-manager', ['앱']); tag('toast-manager', ['앱']); tag('theme-switch', ['앱']);
129	    tag('empty-state', ['앱']); tag('loading-state', ['앱']); tag('error-state', ['앱']);
130	    tag('api-scaffold', ['코드']); tag('entity-gen', ['DB']); tag('migration-plan', ['DB']); tag('cache-tuner', ['DB']);
131	    tag('auth-guard', ['보안']); tag('repo-test', ['테스트']); tag('swagger-doc', ['문서']);
132	    tag('flow-mapper', ['AI']); tag('state-inspector', ['AI']); tag('prototype-runner', ['AI', '앱']); tag('microcopy-ko', ['AI']);
133	    tag('ir-deck', ['문서']); tag('ir-metrics', ['DB']); tag('handoff-notes', ['문서']);
134	
135	    this._skills = arr;
136	    return arr;
137	  }
138	  get skills() { return this.buildSkills(); }
139	  catMap() { const m = {}; this.categoriesData().forEach(c => m[c.key] = c.label); return m; }
140	  statusOf(s) { if (s.claude && s.codex) return s.same ? 'synced' : 'mismatch'; return 'solo'; }
141	
142	  filtered() {
143	    const { folder, category, status, query } = this.state;
144	    const q = (query || '').trim().toLowerCase();
145	    const label = this.catMap()[category];
146	    return this.skills.filter(s => {
147	      if (folder !== 'all' && s.folder !== folder) return false;
148	      if (status === 'attention' && this.statusOf(s) !== 'mismatch') return false;
149	      if (status === 'synced' && this.statusOf(s) !== 'synced') return false;
150	      if (status === 'solo' && this.statusOf(s) !== 'solo') return false;
151	      if (category === 'none' && s.tags.length > 0) return false;
152	      if (category !== 'all' && category !== 'none' && !s.tags.includes(label)) return false;
153	      if (q && !(s.name.toLowerCase().includes(q) || s.folder.toLowerCase().includes(q))) return false;
154	      return true;
155	    });
156	  }
157	
158	  // ---------------- navigation ----------------
159	  go(v) { this.setState({ view: v }); const el = document.querySelector('main'); if (el) el.scrollTop = 0; }
160	  navStyle(v) {
161	    const on = this.state.view === v;
162	    const col = this.state.collapsed || this.state.narrow;
163	    return {
164	      display: 'flex', alignItems: 'center', gap: '12px', width: '100%',
165	      padding: col ? '10px 0' : '9px 12px', borderRadius: '11px', cursor: 'pointer',
166	      justifyContent: col ? 'center' : 'flex-start',
167	      border: '1px solid ' + (on ? 'rgba(0,0,0,.06)' : 'transparent'),
168	      background: on ? '#EEF0F3' : 'transparent',
169	      color: on ? '#1d1d1f' : '#4b4b52',
170	      fontWeight: on ? 600 : 400, fontFamily: 'var(--font-text)',
171	      fontSize: '15px', letterSpacing: '-0.2px',
172	    };
173	  }
174	
175	  // ---------------- diff / sync flow ----------------
176	  openSkillDiff(s) { this.setState({ diffOpen: true, diffKind: 'skill', diffSkill: s, baseline: s.claude ? 'claude' : 'codex' }); }
177	  openInstrDiff() { this.setState({ diffOpen: true, diffKind: 'instructions', diffSkill: null, baseline: 'claude' }); }
178	  closeDiff() { this.setState({ diffOpen: false }); }
179	  setBaseline(b) { this.setState({ baseline: b }); }
180	  applyDiff() {
181	    const s = this.state.diffSkill;
182	    if (s) { s.claude = true; s.codex = true; s.same = true; const sel = { ...this.state.selected }; delete sel[s.name]; this.setState({ selected: sel }); }
183	    this.setState({ diffOpen: false });
184	  }
185	
186	  // ---------------- instructions data ----------------
187	  claudeDoc() {
188	    return [
189	      { n: 1, t: '# 전역 설정 (Global Instructions)', d: true },
190	      { n: 2, t: '', d: false },
191	      { n: 3, t: '## 언어 설정', d: true },
192	      { n: 4, t: '', d: false },
193	      { n: 5, t: '항상 한국어로 답변한다. 기술 용어는 영어 원문을 유지하되, 설명은 자연스러운 한국어로 작성한다.', d: true },
194	      { n: null, t: '', d: false, empty: true },
195	      { n: null, t: '', d: false, empty: true },
196	      { n: 6, t: '## GitHub 계정 (gh CLI 인증)', d: false },
197	      { n: 7, t: '', d: false },
198	      199	      { n: 9, t: '', d: false },
202	      { n: 12, t: '', d: false },
204	    ];
205	  }
206	  codexDoc() {
207	    return [
208	      { n: 1, t: '# Codex Global AGENTS', d: true },
209	      { n: 2, t: '', d: false },
210	      { n: 3, t: '전역에서 에이전트를 쓸 때는 먼저 README.md 를 본다.', d: true },
211	      { n: 4, t: '', d: false },
212	      { n: 5, t: '- 전역 skill 설명과 사용 시점은 `README.md`에 둔다.', d: true },
213	      { n: 6, t: '- 프로젝트별 규칙은 각 프로젝트의 `AGENTS.md`와 `README.md`에 둔다.', d: true },
214	      { n: 7, t: '- 전역 `rules/default.rules`는 공통 정책만 유지한다.', d: true },
215	      { n: 8, t: '## GitHub 계정 (gh CLI 인증)', d: false },
216	      { n: 9, t: '', d: false },
217	      218	      { n: 11, t: '', d: false },
221	      { n: 14, t: '', d: false },
222	      { n: 15, t: 'GitHub 쓰기 작업(issue, PR, comment, review) 전에는 먼저 계정 컨텍스트를 확인한다.', d: true },
223	    ];
224	  }
225	  usageData() {
226	    return [
227	      { name: 'tc-verify', recent: '4일 전', day: 0, week: 1, total: 12 },
228	      { name: 'gh-issue', recent: '6일 전', day: 0, week: 1, total: 9 },
229	      { name: 'closing', recent: '6월 24일', day: 0, week: 0, total: 7 },
230	      { name: 'coaching-manager', recent: '6월 23일', day: 0, week: 0, total: 6 },
231	      { name: 'weekly-retro', recent: '6월 23일', day: 0, week: 0, total: 5 },
232	      { name: 'daily-retro', recent: '6월 17일', day: 0, week: 0, total: 4 },
233	      { name: 'review-pr', recent: '6월 15일', day: 0, week: 0, total: 3 },
234	      { name: 'design-sync-check', recent: '6월 12일', day: 0, week: 0, total: 2 },
235	      { name: 'ui-audit', recent: '6월 9일', day: 0, week: 0, total: 1 },
236	      { name: '01-acm-flow', recent: null, day: 0, week: 0, total: 0 },
237	      { name: '1-2-3-pr-manager-console', recent: null, day: 0, week: 0, total: 0 },
238	      { name: '1-3-reviewer-data-console', recent: null, day: 0, week: 0, total: 0 },
239	      { name: '1-3-reviewer-evidence-collector', recent: null, day: 0, week: 0, total: 0 },
240	      { name: 'tsp-scoreboard', recent: null, day: 0, week: 0, total: 0 },
241	    ];
242	  }
243	
244	  // ---------------- skills view helpers ----------------
245	  toggleSel(name) { const sel = { ...this.state.selected }; if (sel[name]) delete sel[name]; else sel[name] = true; this.setState({ selected: sel }); }
246	  chipStyle(active, muted) {
247	    const base = { display: 'inline-flex', alignItems: 'center', gap: '7px', padding: '7px 13px', borderRadius: '9999px', cursor: 'pointer', fontSize: '13px', letterSpacing: '-0.2px', fontFamily: 'var(--font-text)', whiteSpace: 'nowrap', lineHeight: 1 };
248	    if (active) return { ...base, background: '#1d1d1f', color: '#fff', border: '1px solid #1d1d1f', fontWeight: 600 };
249	    return { ...base, background: muted ? '#fafafa' : '#fff', color: muted ? '#a1a1a6' : '#3a3a3f', border: '1px ' + (muted ? 'dashed #dadade' : 'solid #e0e0e0'), fontWeight: 400 };
250	  }
251	  chipCountStyle(active) { return { fontSize: '12px', fontWeight: 600, color: active ? 'rgba(255,255,255,.55)' : '#b8b8bd' }; }
252	  decMark(has) { return { glyph: has ? '✓' : '–', style: { fontSize: has ? '13.5px' : '15px', fontWeight: has ? 700 : 400, color: has ? '#1d1d1f' : '#cfcfd4', textAlign: 'center', display: 'block' } }; }
253	  decorate(s) {
254	    const st = this.statusOf(s);
255	    let badgeLabel, bg, fg, dot;
256	    if (st === 'synced') { badgeLabel = '동기화됨'; bg = OK_BG; fg = OK; dot = OK_DOT; }
257	    else if (st === 'mismatch') { badgeLabel = '불일치'; bg = WARN_BG; fg = WARN; dot = WARN_DOT; }
258	    else { badgeLabel = '단독'; bg = SOLO_BG; fg = SOLO; dot = SOLO_DOT; }
259	    const sel = !!this.state.selected[s.name];
260	    return {
261	      name: s.name, folder: s.folder,
262	      tags: s.tags.map(t => ({ label: t })), hasTags: s.tags.length > 0, noTags: s.tags.length === 0,
263	      claude: this.decMark(s.claude), codex: this.decMark(s.codex),
264	      badgeLabel, isSynced: st === 'synced', notSynced: st !== 'synced',
265	      badgeStyle: { display: 'inline-flex', alignItems: 'center', gap: '6px', padding: '4px 11px', borderRadius: '9999px', fontSize: '12px', fontWeight: 600, background: bg, color: fg, whiteSpace: 'nowrap' },
266	      dotStyle: { width: '7px', height: '7px', borderRadius: '50%', background: dot, flex: 'none' },
267	      selected: sel, onSel: () => this.toggleSel(s.name), onSync: () => this.openSkillDiff(s),
268	      rowStyle: { display: 'grid', gridTemplateColumns: '24px 104px minmax(130px,1fr) 108px 60px 60px 150px', alignItems: 'center', gap: '8px', padding: '11px 20px', borderBottom: '1px solid #f2f2f4', background: sel ? '#F2F7FE' : (st === 'mismatch' ? '#FCF8EE' : '#fff') },
269	    };
270	  }
271	
272	  renderVals() {
273	    const v = this.state.view;
274	    return {
275	      expanded: !(this.state.collapsed || this.state.narrow),
276	      collapsed: this.state.collapsed || this.state.narrow,
277	      sidebarStyle: {
278	        width: (this.state.collapsed || this.state.narrow) ? '68px' : '256px', flex: 'none',
279	        height: '100vh', background: '#fbfbfd', padding: '18px 14px 16px',
280	        display: 'flex', flexDirection: 'column', transition: 'width .18s cubic-bezier(0.4,0,0.2,1)',
281	      },
282	      skillsGridStyle: this.state.stackSkills
283	        ? { display: 'grid', gridTemplateColumns: '1fr', gap: '14px', alignItems: 'start' }
284	        : { display: 'grid', gridTemplateColumns: '212px 1fr', gap: '16px', alignItems: 'start' },
285	      folderPanelStyle: this.state.stackSkills
286	        ? { background: '#fff', border: '1px solid #e0e0e0', borderRadius: '16px', padding: '14px' }
287	        : { background: '#fff', border: '1px solid #e0e0e0', borderRadius: '16px', padding: '14px', position: 'sticky', top: '112px' },
288	      folderListStyle: this.state.stackSkills
289	        ? { display: 'grid', gridTemplateColumns: 'repeat(auto-fill,minmax(160px,1fr))', gap: '4px', marginTop: '10px' }
290	        : { display: 'flex', flexDirection: 'column', gap: '2px', marginTop: '10px', maxHeight: 'calc(100vh - 260px)', overflowY: 'auto' },
291	      isOverview: v === 'overview', isSkills: v === 'skills',
292	      isInstructions: v === 'instructions', isUsage: v === 'usage', isSpec: v === 'spec',
293	      navOverviewStyle: this.navStyle('overview'),
294	      navInstrStyle: this.navStyle('instructions'),
295	      navSkillsStyle: this.navStyle('skills'),
296	      navUsageStyle: this.navStyle('usage'),
297	      navSpecStyle: this.navStyle('spec'),
298	      goOverview: () => this.go('overview'),
299	      goInstructions: () => this.go('instructions'),
300	      goSkillsNav: () => { this.setState({ status: 'all', folder: 'all', category: 'all' }); this.go('skills'); },
301	      goSkillsAttention: () => { this.setState({ status: 'attention', folder: 'all', category: 'all' }); this.go('skills'); },
302	      goSkillsSynced: () => { this.setState({ status: 'synced', folder: 'all', category: 'all' }); this.go('skills'); },
303	      goSkillsSolo: () => { this.setState({ status: 'solo', folder: 'all', category: 'all' }); this.go('skills'); },
304	      goUsage: () => this.go('usage'),
305	      goSpec: () => this.go('spec'),
306	      toggleCollapse: () => this.setState({ collapsed: !this.state.collapsed }),
307	      noop: () => {},
308	      stopEvt: (e) => { if (e && e.stopPropagation) e.stopPropagation(); },
309	      btnCompact: { padding: '8px 16px', fontSize: '14px' },
310	
311	      // ---- skills ----
312	      folderItems: (() => {
313	        const fq = (this.state.folderQuery || '').trim().toLowerCase();
314	        return this.foldersData().filter(f => !fq || f.label.toLowerCase().includes(fq)).map(f => {
315	          const active = this.state.folder === f.key;
316	          return {
317	            label: f.label, count: f.count, home: !!f.home, notHome: !f.home, onClick: () => this.setState({ folder: f.key }),
318	            style: { display: 'flex', alignItems: 'center', gap: '10px', width: '100%', padding: '8px 11px', borderRadius: '10px', cursor: 'pointer', border: '1px solid ' + (active ? 'rgba(0,0,0,.06)' : 'transparent'), background: active ? '#EEF0F3' : 'transparent', textAlign: 'left', fontFamily: 'var(--font-text)' },
319	            labelStyle: { flex: 1, minWidth: 0, fontSize: '13.5px', letterSpacing: '-0.2px', color: active ? '#1d1d1f' : '#45454c', fontWeight: active ? 600 : 400, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' },
320	            countStyle: { fontSize: '12px', fontWeight: 600, color: active ? '#1d1d1f' : '#b8b8bd', flex: 'none' },
321	          };
322	        });
323	      })(),
324	      categoryChips: this.categoriesData().map(c => {
325	        const active = this.state.category === c.key;
326	        return { label: c.label, count: c.count, onClick: () => this.setState({ category: c.key }), style: this.chipStyle(active, !!c.muted), countStyle: this.chipCountStyle(active) };
327	      }),
328	      statusChips: [{ key: 'attention', label: '주의 필요', count: 3 }, { key: 'all', label: '전체', count: 73 }, { key: 'synced', label: '동기화됨', count: 6 }, { key: 'solo', label: '단독', count: 64 }].map(d => {
329	        const active = this.state.status === d.key;
330	        return { label: d.label, count: d.count, onClick: () => this.setState({ status: d.key }), style: this.chipStyle(active, false), countStyle: this.chipCountStyle(active) };
331	      }),
332	      rows: this.filtered().map(s => this.decorate(s)),
333	      shownCount: this.filtered().length,
334	      isEmpty: this.filtered().length === 0,
335	      totalCount: 73,
336	      searchSmall: { height: '38px' },
337	      syncSelStyle: (() => {
338	        const on = Object.keys(this.state.selected).length > 0;
